#nullable enable // autogenerated

using MVZ2.GameContent.Projectiles;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2.Vanilla.Properties;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.gravelpult)]
    public class Gravelpult : CatapultBehaviour
    {
        public Gravelpult(string nsp, string name) : base(nsp, name)
        {
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            CatapultUpdate(entity);
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            UpdateAnimation(entity);
            entity.SetModelProperty("ThrowsGravel", ThrowsGravel(entity));
        }
        public override void OnThrownTimeout(Entity entity)
        {
            base.OnThrownTimeout(entity);
            SetThrowsGravel(entity, entity.RNG.Next(100) < GRAVEL_CHANCE_PERCENTAGE);
        }
        protected override void PreModifyShootParameters(Entity entity, ref ShootParams param)
        {
            base.PreModifyShootParameters(entity, ref param);
            if (ThrowsGravel(entity))
            {
                param.damage *= 2;
                param.projectileID = VanillaProjectileID.gravel;
            }
            param.spawnParam.SetProperty(VanillaProjectileProps.IGNORE_SHIELDS, true);
        }

        #region  Ù–‘
        public static bool ThrowsGravel(Entity entity) => entity.GetProperty<bool>(PROP_THROWS_GRAVEL);
        public static void SetThrowsGravel(Entity entity, bool value) => entity.SetProperty(PROP_THROWS_GRAVEL, value);
        #endregion

        public static readonly VanillaEntityPropertyMeta<bool> PROP_THROWS_GRAVEL = new VanillaEntityPropertyMeta<bool>("throws_gravel");
        public const int GRAVEL_CHANCE_PERCENTAGE = 25;
    }
}
